256	template<typename T>
257	void ParallelGptDecoder<T>::forward(std::unordered_map<std::string, Tensor>*              output_tensors,
258	                                    const std::unordered_map<std::string, Tensor>*        input_tensors,
259	                                    const std::vector<ParallelGptDecoderLayerWeight<T>*>* gpt_decoder_layer_weight)
260	{
261	    // input tensors:
262	    //      decoder_input [local_batch_size, hidden_dimension],
263	    //      finished [local_batch_size],
264	    //      input_lengths [local_batch_size],
265	    //      total_padding_tokens [local_batch_size]
266	    //      max_input_length [1] on cpu
267	    //      step [1] on cpu
268	    //      ite [1] on cpu
269	    //      cache_indirection [local_batch_size / beam_width, beam_width, memory_len]
270	    //          Here, local_batch_size contains the beam_width, so local_batch_size / beam_width
271	    //          is real local_batch_size. (optional.)
272	    //      masked_tokens [local_batch_size, memory_len]
273	    //      linear_bias_slopes [head_num], optional
274	
275	    // output tensors:
276	    //      decoder_output [local_batch_size, hidden_dimension],
277	    //      key_cache [num_layer, batch_size, head_num, size_per_head // x, memory_len, x]
278	    //      value_cache [num_layer, batch_size, head_num, memory_len, size_per_head]
279	
280	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
281	
282	    FT_CHECK(input_tensors->count("decoder_input"));
283	    FT_CHECK(input_tensors->count("finished"));
284	    FT_CHECK(input_tensors->count("input_lengths"));
285	    FT_CHECK(input_tensors->count("total_padding_tokens"));
286	    FT_CHECK(input_tensors->count("max_input_length"));
287	    FT_CHECK(input_tensors->count("step"));
288	    FT_CHECK(input_tensors->count("ite"));
289	    FT_CHECK(input_tensors->count("masked_tokens"));
290	    FT_CHECK(output_tensors->count("decoder_output"));
291	    FT_CHECK(output_tensors->count("key_cache"));
292	    FT_CHECK(output_tensors->count("value_cache"));
293	
294	    const size_t local_batch_size = input_tensors->at("decoder_input").shape[0];
295	    allocateBuffer(local_batch_size);
296	
297	    const DataType data_type = getTensorType<T>();
298	
299	    const int ite = input_tensors->at("ite").getVal<int>();
300	
301	    Tensor k_cache = output_tensors->at("key_cache");
302	    Tensor v_cache = output_tensors->at("value_cache");
303	
304	    // The resize of the key cache buffer by
305	    //   (local_batch_size, local_head_num, size_per_head // x, max_seq_len, x) where x is constant.
306	    std::vector<size_t> self_k_cache_size(k_cache.shape.begin() + 2, k_cache.shape.end());
307	    self_k_cache_size.insert(self_k_cache_size.begin(), local_batch_size);
308	
309	    // The resize of the value cache buffer by (local_batch_size, local_head_num, max_seq_len, size_per_head).
310	    std::vector<size_t> self_v_cache_size(v_cache.shape.begin() + 2, v_cache.shape.end());
311	    self_v_cache_size.insert(self_v_cache_size.begin(), local_batch_size);
312	
313	    const auto activation_in_type  = int8_mode_ == 2 ? TYPE_INT8 : data_type;
314	    const auto activation_out_type = data_type;
315	
316	    for (uint l = 0; l < num_layer_; l++) {
317	        PUSH_RANGE(fmtstr("layer_%d", l));
318	        bool use_moe = std::find(moe_layer_index_.begin(), moe_layer_index_.end(), l) != moe_layer_index_.end();
319	        if (isValidLayerParallelId(l) == false) {
320	            continue;
321	        }
322	        T* decoder_input = (l == 0) ? input_tensors->at("decoder_input").getPtr<T>() : decoder_layer_output_;
323	        T* decoder_output =
324	            (l == num_layer_ - 1) ? output_tensors->at("decoder_output").getPtr<T>() : decoder_layer_output_;
325	
326	        if (isFirstLayerParallelId(l) == true && pipeline_para_.rank_ != 0 && pipeline_para_.world_size_ > 1) {
327	            size_t data_size = local_batch_size * hidden_units_ / tensor_para_.world_size_;
328	            PUSH_RANGE("input communication");
329	            ftNcclRecv(decoder_input + data_size * tensor_para_.rank_,
330	                       data_size,
331	                       pipeline_para_.rank_ - 1,
332	                       pipeline_para_,
333	                       stream_);
334	            if (tensor_para_.world_size_ > 1) {
335	                PUSH_RANGE("all gather");
336	                ftNcclAllGather(decoder_input, decoder_input, data_size, tensor_para_.rank_, tensor_para_, stream_);
337	                POP_RANGE;
338	            }
339	            POP_RANGE;
340	        }
341	
342	        PUSH_RANGE("pre-mha layernorm");
343	        ParallelGptDecoderLayerWeight<T>* layer_weight = gpt_decoder_layer_weight->at(l);
344	
345	        if (layernorm_type_ == LayerNormType::pre_layernorm) {
346	            invokeGeneralLayerNorm(decoder_normed_input_,
347	                                   decoder_input,
348	                                   layer_weight->pre_layernorm_weights.gamma,
349	                                   layer_weight->pre_layernorm_weights.beta,
350	                                   layernorm_eps_,
351	                                   local_batch_size,
352	                                   hidden_units_,
353	                                   const_cast<float*>(layer_weight->self_attention_weights.query_weight.scale),
354	                                   int8_mode_,
355	                                   stream_);
356	        }
357	        sync_check_cuda_error();
358	        POP_RANGE;
359	
360	        TensorMap self_attention_input_tensors{
361	            {"input_query",
362	             Tensor{MEMORY_GPU,
363	                    activation_in_type,
364	                    {local_batch_size, hidden_units_},
365	                    layernorm_type_ == LayerNormType::pre_layernorm ? decoder_normed_input_ : decoder_input}},
366	            {"finished", input_tensors->at("finished")},
367	            {"sequence_lengths", input_tensors->at("input_lengths")},
368	            {"total_padding_tokens", input_tensors->at("total_padding_tokens")},
369	            {"max_input_length", input_tensors->at("max_input_length")},
370	            {"step", input_tensors->at("step")},
371	            {"masked_tokens", input_tensors->at("masked_tokens")}};
372	        if (input_tensors->count("cache_indirection")) {
373	            self_attention_input_tensors.insert("cache_indirection", input_tensors->at("cache_indirection"));
374	        }
375	        if (input_tensors->count("linear_bias_slopes")) {
376	            self_attention_input_tensors.insert("linear_bias_slopes", input_tensors->at("linear_bias_slopes"));
377	        }
378	
379	        size_t cache_offset = l - getFirstLayerParallelId();
380	        for (auto t = k_cache.shape.begin() + 1; t != k_cache.shape.end(); ++t) {
381	            cache_offset *= *t;
382	        };
383	        size_t ite_cache_offset = ite * local_batch_size;
384	        for (auto t = k_cache.shape.begin() + 2; t != k_cache.shape.end(); ++t) {
385	            ite_cache_offset *= *t;
386	        }
387	        cache_offset += ite_cache_offset;
388	
389	        TensorMap self_attention_output_tensors{
390	            {"hidden_features",
391	             Tensor(MEMORY_GPU, activation_out_type, {local_batch_size, hidden_units_}, self_attn_output_)},
392	            {"key_cache", Tensor(MEMORY_GPU, data_type, self_k_cache_size, k_cache.getPtrWithOffset<T>(cache_offset))},
393	            {"value_cache",
394	             Tensor(MEMORY_GPU, data_type, self_v_cache_size, v_cache.getPtrWithOffset<T>(cache_offset))}};
395	
396	        self_attention_layer_->forward(
397	            &self_attention_output_tensors, &self_attention_input_tensors, &layer_weight->self_attention_weights);
398	
399	        // the adapter after attention
400	        PUSH_RANGE("post mha layernorm");
401	        if (has_adapters_) {
402	            invokeGenericActivation<IdentityActivation, T, T>(
403	                self_attn_output_,
404	                layer_weight->self_attention_weights.attention_output_weight.bias,
405	                nullptr,
406	                nullptr,
407	                nullptr,
408	                nullptr,
409	                local_batch_size,
410	                hidden_units_,
411	                0,
412	                nullptr,
413	                nullptr,
414	                stream_);
415	
416	            TensorMap ffn_input_tensors(
417	                {{"ffn_input", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, self_attn_output_}}});
418	            TensorMap ffn_output_tensors(
419	                {{"ffn_output",
420	                  Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, after_adapter_attn_output_}}});
421	
422	            ffn_layer_->resetInterSize(adapter_inter_size_ / tensor_para_.world_size_);
423	            ffn_layer_->forward(
424	                &ffn_output_tensors, &ffn_input_tensors, &layer_weight->after_attention_adapter_weights);
425	        }
426	
427	        if (layernorm_type_ == LayerNormType::pre_layernorm) {
428	            invokeGeneralAddBiasResidualPreLayerNorm(
429	                // in case of has_adaptor false isn't it self_attn_output_? i.e.
430	                //   has_adapters_ ? after_adapter_attn_outpu_ : self_attn_output_,
431	                has_adapters_ ? after_adapter_attn_output_ : self_attn_output_,
432	                normed_self_attn_output_,
433	                has_adapters_ ? after_adapter_attn_output_ : self_attn_output_,
434	                decoder_input,
435	                has_adapters_ ? self_attn_output_ : nullptr,
436	                layer_weight->self_attn_layernorm_weights.gamma,
437	                layer_weight->self_attn_layernorm_weights.beta,
438	                has_adapters_ ? layer_weight->after_attention_adapter_weights.output_weight.bias :
439	                                layer_weight->self_attention_weights.attention_output_weight.bias,
440	                layernorm_eps_,
441	                local_batch_size,
442	                hidden_units_,
443	                nullptr,
444	                nullptr,
445	                const_cast<float*>(layer_weight->ffn_weights.intermediate_weight.scale),
446	                (float*)nullptr,
447	                int8_mode_,
448	                stream_);
449	        }
450	        else if (layernorm_type_ == LayerNormType::post_layernorm) {
451	            invokeAddBiasResidualLayerNorm(
452	                // check correctness.
453	                after_adapter_attn_output_,
454	                decoder_input,
455	                has_adapters_ ? layer_weight->after_attention_adapter_weights.output_weight.bias :
456	                                layer_weight->self_attention_weights.attention_output_weight.bias,
457	                layer_weight->pre_layernorm_weights.gamma,
458	                layer_weight->pre_layernorm_weights.beta,
459	                layernorm_eps_,
460	                local_batch_size,
461	                hidden_units_,
462	                stream_);
463	        }
464	
465	        sync_check_cuda_error();
466	        POP_RANGE;
467	
468	        T* ffn_output_ptr = has_adapters_ ? self_attn_output_ : decoder_output;
469	
470	        TensorMap ffn_input_tensors(
471	            {{"ffn_input",
472	              Tensor{MEMORY_GPU,
473	                     activation_in_type,
474	                     {local_batch_size, hidden_units_},
475	                     layernorm_type_ == LayerNormType::pre_layernorm ? normed_self_attn_output_ :
476	                                                                       after_adapter_attn_output_}}});
477	        TensorMap ffn_output_tensors;
478	        if (!use_moe) {
479	            ffn_output_tensors.insert(
480	                "ffn_output",
481	                Tensor{MEMORY_GPU, activation_out_type, {local_batch_size, hidden_units_}, ffn_output_ptr});
482	        }
483	        else {
484	            ffn_input_tensors.insert("moe_k", Tensor{MEMORY_CPU, TYPE_UINT64, {1}, &moe_k_});
485	
486	            ffn_output_tensors.insert("ffn_output",
487	                                      Tensor{MEMORY_GPU,
488	                                             activation_out_type,
489	                                             {moe_k_ * local_batch_size, hidden_units_},
490	                                             has_adapters_ ? adapter_fc2_result_ : fc2_result_});
491	            ffn_output_tensors.insert(
492	                "expert_scales", Tensor{MEMORY_GPU, activation_out_type, {local_batch_size, moe_k_}, expert_scales_});
493	            ffn_output_tensors.insert(
494	                "expanded_source_row_to_expanded_dest_row",
495	                Tensor{MEMORY_GPU, TYPE_INT32, {local_batch_size, moe_k_}, expanded_source_row_to_expanded_dest_row_});
496	            ffn_output_tensors.insert(
497	                "expert_for_source_row",
498	                Tensor{MEMORY_GPU, TYPE_INT32, {local_batch_size, moe_k_}, expert_for_source_row_});
499	        }
500	
501	        ffn_layer_->resetInterSize(inter_size_ / tensor_para_.world_size_);
502	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &layer_weight->ffn_weights);
503	
504	        // the adapter after ffn
505	        PUSH_RANGE("post ffn");
506	        if (has_adapters_) {
507	            TensorMap ffn_input_tensors;
508	            TensorMap ffn_output_tensors;
509	            if (!use_moe) {
510	                invokeGenericActivation<IdentityActivation, T, T>(ffn_output_ptr,
511	                                                                  layer_weight->ffn_weights.output_weight.bias,
512	                                                                  nullptr,
513	                                                                  nullptr,
514	                                                                  nullptr,
515	                                                                  nullptr,
516	                                                                  local_batch_size,
517	                                                                  hidden_units_,
518	                                                                  0,
519	                                                                  nullptr,
520	                                                                  nullptr,
521	                                                                  stream_);
522	
523	                ffn_input_tensors.insert(
524	                    "ffn_input", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, ffn_output_ptr});
525	                ffn_output_tensors.insert(
526	                    "ffn_output", Tensor{MEMORY_GPU, data_type, {local_batch_size, hidden_units_}, decoder_output});
527	            }
528	            else {
529	                invokeGenericActivation<IdentityActivation, T, T>(adapter_fc2_result_,
530	                                                                  layer_weight->ffn_weights.output_weight.bias,
531	                                                                  nullptr,
532	                                                                  nullptr,
533	                                                                  nullptr,
534	                                                                  nullptr,
535	                                                                  moe_k_ * local_batch_size,
536	                                                                  hidden_units_,
537	                                                                  0,
538	                                                                  nullptr,
539	                                                                  nullptr,
540	                                                                  stream_);
541	
542	                ffn_input_tensors.insert(
543	                    "ffn_input",
544	                    Tensor{MEMORY_GPU, data_type, {moe_k_ * local_batch_size, hidden_units_}, adapter_fc2_result_});
545	                ffn_output_tensors.insert(
546	                    "ffn_output",
547	                    Tensor{MEMORY_GPU, data_type, {moe_k_ * local_batch_size, hidden_units_}, fc2_result_});
548	            }
549	
550	            ffn_layer_->resetInterSize(adapter_inter_size_ / tensor_para_.world_size_);
551	            ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &layer_weight->after_ffn_adapter_weights);
552	        }
553	
554	        if (!use_moe) {
555	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
556	                invokeAddBiasResidual(decoder_output,
557	                                      decoder_output,
558	                                      after_adapter_attn_output_,
559	                                      has_adapters_ ? ffn_output_ptr : nullptr,
560	                                      has_adapters_ ? layer_weight->after_ffn_adapter_weights.output_weight.bias :
561	                                                      layer_weight->ffn_weights.output_weight.bias,
562	                                      nullptr,
563	                                      nullptr,
564	                                      local_batch_size,
565	                                      hidden_units_,
566	                                      stream_);
567	            }
568	            else if (layernorm_type_ == LayerNormType::post_layernorm) {
569	                invokeAddBiasResidualLayerNorm(decoder_output,
570	                                               after_adapter_attn_output_,
571	                                               has_adapters_ ?
572	                                                   layer_weight->after_ffn_adapter_weights.output_weight.bias :
573	                                                   layer_weight->ffn_weights.output_weight.bias,
574	                                               layer_weight->self_attn_layernorm_weights.gamma,
575	                                               layer_weight->self_attn_layernorm_weights.beta,
576	                                               layernorm_eps_,
577	                                               local_batch_size,
578	                                               hidden_units_,
579	                                               stream_);
580	            }
581	        }
582	        else {
583	            if (layernorm_type_ == LayerNormType::pre_layernorm) {
584	                finalize_moe_routing_kernelLauncher(fc2_result_,
585	                                                    decoder_output,
586	                                                    after_adapter_attn_output_,
587	                                                    has_adapters_ ? ffn_output_ptr : nullptr,
588	                                                    has_adapters_ ?
589	                                                        layer_weight->after_ffn_adapter_weights.output_weight.bias :
590	                                                        layer_weight->ffn_weights.output_weight.bias,
591	                                                    expert_scales_,
592	                                                    expanded_source_row_to_expanded_dest_row_,
593	                                                    expert_for_source_row_,
594	                                                    local_batch_size,
595	                                                    hidden_units_,
596	                                                    moe_k_,
597	                                                    stream_);
598	            }
599	            else if (layernorm_type_ == LayerNormType::post_layernorm) {
600	                finalize_moe_routing_kernelLauncher(fc2_result_,
601	                                                    decoder_output,
602	                                                    after_adapter_attn_output_,
603	                                                    has_adapters_ ?
604	                                                        layer_weight->after_ffn_adapter_weights.output_weight.bias :
605	                                                        layer_weight->ffn_weights.output_weight.bias,
606	                                                    expert_scales_,
607	                                                    expanded_source_row_to_expanded_dest_row_,
608	                                                    expert_for_source_row_,
609	                                                    local_batch_size,
610	                                                    hidden_units_,
611	                                                    moe_k_,
612	                                                    stream_);
613	                invokeGeneralLayerNorm(decoder_output,
614	                                       decoder_output,
615	                                       layer_weight->self_attn_layernorm_weights.gamma,
616	                                       layer_weight->self_attn_layernorm_weights.beta,
617	                                       layernorm_eps_,
618	                                       local_batch_size,
619	                                       hidden_units_,
620	                                       (float*)nullptr,
621	                                       0,
622	                                       stream_);
623	            }
624	        }
625	        sync_check_cuda_error();
626	        POP_RANGE;
627	
628	        PUSH_RANGE("Nccl send");
629	        if (isLastLayerParallelId(l) == true && pipeline_para_.rank_ != pipeline_para_.world_size_ - 1
630	            && pipeline_para_.world_size_ > 1) {
631	
632	            ftNcclSend(decoder_output
633	                           + local_batch_size * hidden_units_ / tensor_para_.world_size_ * tensor_para_.rank_,
634	                       local_batch_size * hidden_units_ / tensor_para_.world_size_,
635	                       pipeline_para_.rank_ + 1,
636	                       pipeline_para_,
637	                       stream_);
638	        }
639	        POP_RANGE;
640	        POP_RANGE;
641	    }
642	
643	    if (is_free_buffer_after_forward_ == true) {
644	        freeBuffer();
645	    }
646	}
647	
648	template class ParallelGptDecoder<float>;
649	template class ParallelGptDecoder<half>;
650	#ifdef ENABLE_BF16
651	template class ParallelGptDecoder<__nv_bfloat16>;
652	#endif
653	
654	}  // namespace fastertransformer
