119	template<typename T>
120	void invokeInputIdsEmbeddingLookupPosEncoding(T*                    from_tensor,
121	                                              int*                  output_ids,
122	                                              const T*              embedding_table,  // can also be inputs_embeds
123	                                              const T*              pos_table,
124	                                              pPromptTuningParam<T> prompt_param,
125	                                              const int*            input_ids,
126	                                              const int             start_step,
127	                                              const int             length,
128	                                              const int             max_length,
129	                                              const int             batch_size,
130	                                              const int             hidden_units,
131	                                              cudaStream_t          stream)
132	{
133	    dim3       grid(min(batch_size * length, 65536));
134	    dim3       block(min(hidden_units, 512));
135	    const bool has_output_ids = output_ids != nullptr;
136	    FT_CHECK(!(has_output_ids && input_ids == nullptr));
137	
138	    if (has_output_ids) {
139	        if (prompt_param.use_request_p_prompt_embedding) {
140	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(true, 2);
141	        }
142	        else if (prompt_param.p_prompt_tuning_batch_weights != nullptr) {
143	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(true, 1);
144	        }
145	        else {
146	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(true, 0);
147	        }
148	    }
149	    else {
150	        if (prompt_param.use_request_p_prompt_embedding) {
151	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(false, 2);
152	        }
153	        else if (prompt_param.p_prompt_tuning_batch_weights != nullptr) {
154	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(false, 1);
155	        }
156	        else {
157	            WORD_POS_EMBEDDING_LOOPUP_KERNEL(false, 0);
158	        }
159	    }
