296	template<typename T>
297	__global__ void transposeAxis01(T* out, T* in, const int dim0, const int dim1, const int dim2)
298	{
299	    int index = threadIdx.x + blockIdx.x * blockDim.x;
300	    if (index < dim0 * dim1 * dim2) {
301	        const int input_dim2_index = index % dim2;
302	        index                      = (index - input_dim2_index) / dim2;
303	        const int input_dim1_index = index % dim1;
304	        index                      = (index - input_dim1_index) / dim1;
305	        const int input_dim0_index = index % dim0;
306	
307	        out[input_dim1_index * dim0 * dim2 + input_dim0_index * dim2 + input_dim2_index] =
308	            in[input_dim0_index * dim1 * dim2 + input_dim1_index * dim2 + input_dim2_index];
309	    }
310	}
