329	template<typename T>
330	__global__ void transposeAxis01(T* out, T* in, const int* in_skipping_dim1, const int dim0, const int dim1)
331	{
332	    // out: [dim1, dim0]
333	    // in: [dim0, dim1]
334	    // in_skipping_dim1: [dim1]
335	
336	    int index = threadIdx.x + blockIdx.x * blockDim.x;
337	    if (index < dim0 * dim1) {
338	        const int input_dim1_index = index % dim1;
339	        index                      = (index - input_dim1_index) / dim1;
340	        const int input_dim0_index = index % dim0;
341	        const int in_offset        = in_skipping_dim1 == nullptr ? 0 : in_skipping_dim1[input_dim1_index] * dim1;
342	
343	        out[input_dim1_index * dim0 + input_dim0_index] = in[in_offset + input_dim0_index * dim1 + input_dim1_index];
344	    }
345	}
