359	template<typename T, bool PREFIX_PROMPT>
360	__global__ void buildDecoderAttentionMaskKernel(T*         attention_mask,
361	                                                const int* sequence_lengths,
362	                                                const int* prefix_prompt_lengths,
363	                                                const int  max_seq_len,
364	                                                const int  max_prompt_length)
365	{
366	    // sequence_lengths: [batch_size]
367	    // attention_mask: [batch_size, 1, max_seq_len, max_seq_len + max_prompt_length]
368	    const int max_prompt_seq_length = max_seq_len + max_prompt_length;
369	    const int mask_size_per_seq     = max_seq_len * max_prompt_seq_length;
370	    attention_mask += blockIdx.x * mask_size_per_seq;
371	    const int seq_length    = sequence_lengths[blockIdx.x];
372	    const int prompt_length = PREFIX_PROMPT ? prefix_prompt_lengths[blockIdx.x] : 0;
373	    for (int i = threadIdx.x; i < mask_size_per_seq; i += blockDim.x) {
374	        int row_id = i / max_prompt_seq_length;
375	        int col_id = i % max_prompt_seq_length;
376	        if (row_id < seq_length && col_id <= (row_id + prompt_length)) {
377	            attention_mask[i] = (T)(1.0f);
378	        }
379	        else {
380	            attention_mask[i] = (T)(0.0f);
381	        }
382	    }
383	}
