695	__global__ void init_shared_contexts(int* shared_contexts, const size_t batch_size)
696	{
697	    const int global_idx = blockIdx.x * blockDim.x + threadIdx.x;
698	    if (global_idx >= batch_size) {
699	        return;
700	    }
701	    shared_contexts[global_idx] = global_idx;
702	}
