736	template<typename T>
737	__global__ void compact_inputs(T*         compact_input,
738	                               T*         compact_attention_mask,
739	                               int*       compact_input_lengths,
740	                               const T*   decoder_input,
741	                               const T*   decoder_mask,
742	                               const int* input_lengths,
743	                               const int* compact_idx,
744	                               size_t     compact_size,
745	                               size_t     seq_len,
746	                               size_t     hidden_dimension)
747	{
748	    const int global_idx = blockIdx.x * blockDim.x + threadIdx.x;
749	
750	    if (global_idx < compact_size * seq_len * hidden_dimension) {
751	        const int h_id     = global_idx % hidden_dimension;
752	        const int seq_id   = (global_idx / hidden_dimension) % seq_len;
753	        const int batch_id = global_idx / (hidden_dimension * seq_len);
754	
755	        compact_input[global_idx] = decoder_input[(compact_idx[batch_id] * seq_len + seq_id) * hidden_dimension + h_id];
756	    }
757	
758	    if (global_idx < compact_size * seq_len * seq_len) {
759	        const int seq1_id  = global_idx % seq_len;
760	        const int seq2_id  = (global_idx / seq_len) % seq_len;
761	        const int batch_id = global_idx / (seq_len * seq_len);
762	
763	        compact_attention_mask[global_idx] =
764	            decoder_mask[(compact_idx[batch_id] * seq_len + seq2_id) * seq_len + seq1_id];
765	    }
766	
767	    if (global_idx < compact_size) {
768	        compact_input_lengths[global_idx] = input_lengths[compact_idx[global_idx]];
769	    }
770	}
