772	template<typename T>
773	void invokeCompactInputs(T*           compact_input,
774	                         T*           compact_attention_mask,
775	                         int*         compact_input_lengths,
776	                         const T*     decoder_input,
777	                         const T*     decoder_mask,
778	                         const int*   input_lengths,
779	                         const int*   compact_idx,
780	                         size_t       compact_size,
781	                         size_t       seq_len,
782	                         size_t       hidden_dimension,
783	                         cudaStream_t stream)
784	{
785	    /* Compact relevant decoder_layer inputs based on the identical contexts.
786	     * For example, decoder_input is [batch_size, seq_len, H]. It's compacted
787	     * into compact_input [compact_size, seq_len, H] such that
788	     * compact_input[i, ...] = decoder_input[compact_idx[i], ...] */
789	    const size_t elems_n = compact_size * seq_len * max(hidden_dimension, seq_len);
790	    const dim3   blockDim(512);
791	    const dim3   gridDim((elems_n + 512 - 1) / 512);
792	
793	    compact_inputs<T><<<gridDim, blockDim, 0, stream>>>(compact_input,
794	                                                        compact_attention_mask,
795	                                                        compact_input_lengths,
796	                                                        decoder_input,
797	                                                        decoder_mask,
798	                                                        input_lengths,
799	                                                        compact_idx,
800	                                                        compact_size,
801	                                                        seq_len,
802	                                                        hidden_dimension);
803	}
