824	template<typename T>
825	__global__ void uncompact_outputs(T*         uncompact_buffer,
826	                                  const T*   compact_buffer,
827	                                  const int* batch_to_compact_idx,
828	                                  size_t     batch_size,
829	                                  size_t     buffer_stride)
830	{
831	    /* Uncompact a buffer IN of size [Compact, Stride] into OUT of size [Batch, Stride]
832	     * so that \forall i, OUT[i, :] = IN[batch_to_compact_idx[i], :]
833	     */
834	    const int global_idx = blockIdx.x * blockDim.x + threadIdx.x;
835	
836	    if (global_idx >= batch_size * buffer_stride) {
837	        return;
838	    }
839	
840	    const int stride_idx = global_idx % buffer_stride;
841	    const int batch_idx  = global_idx / buffer_stride;
842	
843	    const int src                = batch_to_compact_idx[batch_idx];
844	    uncompact_buffer[global_idx] = compact_buffer[src * buffer_stride + stride_idx];
845	}
