38	                                                                          is_free_buffer_after_forward_,
39	                                                                          is_qk_buf_float_,
40	                                                                          sparse_,
41	                                                                          int8_mode_,
42	                                                                          custom_all_reduce_comm_,
43	                                                                          enable_custom_all_reduce_);
44	
45	    bool use_gated_activation = activation_type_ == ActivationType::GeGLU || activation_type_ == ActivationType::ReGLU;
46	    size_t max_inter_size     = has_adapters_ ? std::max(inter_size_, adapter_inter_size_) : inter_size_;
47	    if (activation_type_ == ActivationType::Gelu || activation_type_ == ActivationType::GeGLU) {
48	        ffn_layer_ = new TensorParallelGeluFfnLayer<T>(max_batch_size_,
49	                                                       max_seq_len_,
50	                                                       head_num_,
51	                                                       size_per_head_,
52	                                                       expert_num_,  // expert_num
53	                                                       max_inter_size,
54	                                                       tensor_para_,
55	                                                       stream_,
56	                                                       cublas_wrapper_,
57	                                                       allocator_,
58	                                                       true,
59	                                                       is_free_buffer_after_forward_,
60	                                                       sparse_,
61	                                                       int8_mode_,
62	                                                       use_gated_activation,
63	                                                       custom_all_reduce_comm_,
64	                                                       enable_custom_all_reduce_);
65	    }
66	    else if (activation_type_ == ActivationType::Relu || activation_type_ == ActivationType::ReGLU) {
67	        ffn_layer_ = new TensorParallelReluFfnLayer<T>(max_batch_size_,
68	                                                       max_seq_len_,
69	                                                       head_num_,
70	                                                       size_per_head_,
71	                                                       expert_num_,  // expert_num
72	                                                       max_inter_size,
73	                                                       tensor_para_,
74	                                                       stream_,
75	                                                       cublas_wrapper_,
76	                                                       allocator_,
77	                                                       true,
78	                                                       is_free_buffer_after_forward_,
79	                                                       sparse_,
80	                                                       int8_mode_,
81	                                                       use_gated_activation,
82	                                                       custom_all_reduce_comm_,
83	                                                       enable_custom_all_reduce_);
84	    }
